// Quick, human-readable summary of what Salesforce returned.
// The raw rows are on the "Run SOQL" node; this just makes them easy to scan.
const rows = $input.all().map((i) => i.json);
const soql = $('✏️ SOQL — edit me').first().json.soql;

// Field list = union of keys across the returned rows (minus Salesforce's attributes blob).
const fields = [...new Set(rows.flatMap((r) => Object.keys(r)))].filter((k) => k !== 'attributes');

return [{
  json: {
    soql,
    rowCount: rows.length,
    fields,
    note: rows.length === 0
      ? 'No rows. If you expected data, check the WHERE clause; if the query ERRORED instead, that field/object likely does not exist in this org.'
      : 'Open the "Run SOQL" node to see the full rows.',
    firstRow: rows[0] || null,
  },
}];
